'use client'

import { useEffect, useRef, useState } from 'react'
import { CheckCircle } from 'lucide-react'

export default function Experience() {
  const [isVisible, setIsVisible] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
        }
      },
      { threshold: 0.1 }
    )

    if (ref.current) {
      observer.observe(ref.current)
    }

    return () => observer.disconnect()
  }, [])

  const experiences = [
    {
      company: 'ROVA',
      role: 'Senior Frontend Engineer',
      period: '2025 - Present',
      description: 'Developed and maintained client-facing applications',
      achievements: [
        'Built an internet banking platform for FCMB UK serving thousands of daily users',
        'Wrote automated tests ensuring at least 85% coverage',
        'Collaborated with designers to ensure pixel-perfect implementation',
        'Partnered closely with FCMB UK stakeholders to align features and delivery',
        'Worked with DevOps engineers to streamline deployments and monitoring',
      ],
    },
    {
      company: 'Tech service',
      role: 'Frontend Engineer',
      period: '2024 - 2025',
      description: 'Developed and maintained client-facing applications',
      achievements: [
        'Built a core banking website serving thousands of daily users',
        'Implemented comprehensive testing strategy (Jest, React Testing Library)',
        'Collaborated with designers to ensure pixel-perfect implementation',
        'Optimized API calls reducing load times by 50%',
      ],
    },
    {
      company: 'MKAN',
      role: 'Frontend Developer',
      period: '2021 - 2023',
      description: 'Developed and maintained client-facing applications',
      achievements: [
        'Built responsive web applications serving 40K+ users',
        'Implemented comprehensive testing strategy (Jest, React Testing Library)',
        'Collaborated with designers to ensure pixel-perfect implementation',
        'Optimized API calls reducing load times by 50%',
      ],
    },
  ]

  return (
    <section
      id="experience"
      ref={ref}
      className="py-20 px-6 bg-card/50"
    >
      <div className="max-w-4xl mx-auto">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold text-foreground mb-4">
            Experience
          </h2>
          <p className="text-muted-foreground text-lg">
            My professional journey and achievements
          </p>
        </div>

        <div className="space-y-8 relative">
          {/* Timeline Line */}
          <div className="absolute left-4 md:left-1/2 top-0 bottom-0 w-1 bg-accent/30 md:transform md:-translate-x-1/2" />

          {/* Timeline Items */}
          {experiences.map((exp, idx) => (
            <div
              key={exp.company}
              className={`relative ${idx % 2 === 0 ? '' : 'md:ml-auto'} md:w-1/2 pl-12 md:pl-0 ${
                idx % 2 === 0 ? 'md:pr-12' : 'md:pl-12'
              } transition-all duration-700`}
              style={{
                opacity: isVisible ? 1 : 0,
                transform: isVisible
                  ? 'translateY(0)'
                  : 'translateY(20px)',
                transitionDelay: isVisible ? `${idx * 150}ms` : '0ms',
              }}
            >
              {/* Timeline Dot */}
              <div className="absolute left-0 md:left-1/2 top-2 md:transform md:-translate-x-1/2 md:-translate-y-1/2 w-8 h-8 rounded-full bg-accent border-4 border-background flex items-center justify-center md:top-6">
                <div className="w-3 h-3 rounded-full bg-accent-foreground" />
              </div>

              {/* Content Card */}
              <div className="rounded-lg border border-accent/30 bg-background p-6 hover:border-accent/50 hover:bg-accent/5 transition-all hover:shadow-lg hover:shadow-accent/10">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <h3 className="text-xl font-bold text-accent">
                      {exp.role}
                    </h3>
                    <p className="text-foreground font-semibold">{exp.company}</p>
                  </div>
                  <span className="text-sm text-muted-foreground font-mono bg-card px-3 py-1 rounded">
                    {exp.period}
                  </span>
                </div>

                <p className="text-muted-foreground mb-4">{exp.description}</p>

                {/* Achievements */}
                <ul className="space-y-2">
                  {exp.achievements.map((achievement) => (
                    <li
                      key={achievement}
                      className="flex gap-3 text-sm text-muted-foreground"
                    >
                      <CheckCircle size={16} className="text-accent mt-0.5 flex-shrink-0" />
                      <span>{achievement}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
