'use client'

import { useState, useEffect } from 'react'
import { Menu, X, Download } from 'lucide-react'

const NAV_LINKS = [
  { label: 'About', id: 'about' },
  { label: 'Projects', id: 'projects' },
  { label: 'Experience', id: 'experience' },
  { label: 'Contact', id: 'contact' },
] as const

export default function Navigation() {
  const [isOpen, setIsOpen] = useState(false)
  const [isScrolled, setIsScrolled] = useState(false)

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50)
    window.addEventListener('scroll', handleScroll, { passive: true })
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  const scrollToSection = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' })
    setIsOpen(false)
  }

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 animate-slide-down ${
        isScrolled
          ? 'bg-white/80 backdrop-blur-lg border-b border-border shadow-sm'
          : 'bg-transparent'
      }`}
    >
      <div className="max-w-6xl mx-auto px-6 py-4 flex justify-between items-center">
        <a
          href="#"
          className="text-xl font-bold text-foreground tracking-tight hover:text-accent transition-colors"
        >
          Yusuf<span className="text-accent">.</span>
        </a>

        <div className="hidden md:flex gap-8 items-center">
          {NAV_LINKS.map((link) => (
            <button
              key={link.id}
              onClick={() => scrollToSection(link.id)}
              className="text-muted-foreground hover:text-foreground transition-colors text-sm font-medium"
            >
              {link.label}
            </button>
          ))}
          <a
            href="/resume.pdf"
            download="Yusuf_Abdullahi_Resume.pdf"
            className="px-4 py-2 bg-accent text-white rounded-lg text-sm font-semibold flex items-center gap-2 hover:bg-accent/90 transition-colors"
          >
            <Download size={15} />
            Resume
          </a>
        </div>

        <button
          onClick={() => setIsOpen(!isOpen)}
          className="md:hidden text-foreground hover:text-accent transition-colors"
          aria-label={isOpen ? 'Close menu' : 'Open menu'}
        >
          {isOpen ? <X size={22} /> : <Menu size={22} />}
        </button>
      </div>

      {isOpen && (
        <div className="md:hidden bg-white border-b border-border">
          <div className="px-6 py-4 space-y-1">
            {NAV_LINKS.map((link) => (
              <button
                key={link.id}
                onClick={() => scrollToSection(link.id)}
                className="block w-full text-left py-2 text-muted-foreground hover:text-foreground transition-colors text-sm font-medium"
              >
                {link.label}
              </button>
            ))}
            <a
              href="/resume.pdf"
              download="Yusuf_Abdullahi_Resume.pdf"
              className="mt-3 w-full px-4 py-2 bg-accent text-white rounded-lg text-sm font-semibold flex items-center justify-center gap-2 hover:bg-accent/90 transition-colors"
            >
              <Download size={15} />
              Download Resume
            </a>
          </div>
        </div>
      )}
    </nav>
  )
}
