'use client'

import { useEffect, useRef, useState } from 'react'
import { Code2, Palette, Zap, Shield, Globe, Layers } from 'lucide-react'

export default function About() {
  const [isVisible, setIsVisible] = useState(false)
  const [hoveredSkill, setHoveredSkill] = useState<number | null>(null)
  const ref = useRef(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
        }
      },
      { threshold: 0.1 }
    )

    if (ref.current) {
      observer.observe(ref.current)
    }

    return () => observer.disconnect()
  }, [])

  const skills = [
    { name: 'Component Architecture', icon: Layers, stat: '50+', label: 'Components Built' },
    { name: 'Performance Optimization', icon: Zap, stat: '3x', label: 'Faster Load Times' },
    { name: 'Design Systems', icon: Palette, stat: '5+', label: 'Systems Created' },
    { name: 'Accessibility', icon: Shield, stat: 'WCAG', label: '2.1 Compliant' },
    { name: 'API Integration', icon: Globe, stat: '20+', label: 'APIs Integrated' },
    { name: 'State Management', icon: Code2, stat: '4+', label: 'Years Experience' },
  ]

  return (
    <section
      id="about"
      ref={ref}
      className="min-h-screen flex items-center justify-center py-20 px-6"
    >
      <div className="max-w-5xl w-full">
        {/* Section Header */}
        <div
          className="text-center mb-16"
          style={{
            opacity: isVisible ? 1 : 0,
            transform: isVisible ? 'translateY(0)' : 'translateY(30px)',
            transition: 'all 0.8s cubic-bezier(0.16, 1, 0.3, 1)',
          }}
        >
          <p className="text-accent text-sm font-mono tracking-widest uppercase mb-3">
            About Me
          </p>
          <h2 className="text-4xl md:text-5xl font-bold text-foreground mb-6">
            Crafting Digital Experiences
          </h2>
          <div className="w-16 h-1 bg-accent mx-auto rounded-full" />
        </div>

        {/* Bio Content */}
        <div
          className="max-w-3xl mx-auto mb-16 space-y-6"
          style={{
            opacity: isVisible ? 1 : 0,
            transform: isVisible ? 'translateY(0)' : 'translateY(30px)',
            transition: 'all 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.2s',
          }}
        >
          <p className="text-muted-foreground text-lg leading-relaxed text-center">
            I'm a passionate frontend engineer with{' '}
            <span className="text-accent font-semibold">4+ years of experience</span>{' '}
            building scalable web applications. I specialize in crafting beautiful,
            accessible, and performant user interfaces that solve real-world problems.
          </p>
          <p className="text-muted-foreground text-lg leading-relaxed text-center">
            My expertise spans across modern frontend technologies, responsive design,
            and creating design systems that scale. I'm passionate about clean code,
            best practices, and mentoring junior developers.
          </p>
        </div>

        {/* Skills Grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 md:gap-6">
          {skills.map((skill, idx) => {
            const Icon = skill.icon
            return (
              <div
                key={skill.name}
                onMouseEnter={() => setHoveredSkill(idx)}
                onMouseLeave={() => setHoveredSkill(null)}
                className="relative group cursor-default"
                style={{
                  opacity: isVisible ? 1 : 0,
                  transform: isVisible ? 'translateY(0) scale(1)' : 'translateY(30px) scale(0.95)',
                  transition: `all 0.6s cubic-bezier(0.16, 1, 0.3, 1) ${0.3 + idx * 0.1}s`,
                }}
              >
                <div
                  className={`relative overflow-hidden rounded-xl border bg-card p-6 transition-all duration-500 ${
                    hoveredSkill === idx
                      ? 'border-accent shadow-lg shadow-accent/10 -translate-y-2'
                      : 'border-accent/20 hover:border-accent/40'
                  }`}
                >
                  {/* Animated background pulse */}
                  <div
                    className={`absolute inset-0 bg-accent/5 transition-opacity duration-500 ${
                      hoveredSkill === idx ? 'opacity-100' : 'opacity-0'
                    }`}
                  />

                  <div className="relative">
                    {/* Icon */}
                    <div
                      className={`w-12 h-12 rounded-lg bg-accent/10 border border-accent/20 flex items-center justify-center mb-4 transition-all duration-500 ${
                        hoveredSkill === idx ? 'scale-110 bg-accent/20 border-accent/40' : ''
                      }`}
                    >
                      <Icon
                        size={22}
                        className={`transition-colors duration-300 ${
                          hoveredSkill === idx ? 'text-accent' : 'text-muted-foreground'
                        }`}
                      />
                    </div>

                    {/* Stat */}
                    <p
                      className={`text-2xl font-bold mb-1 transition-colors duration-300 ${
                        hoveredSkill === idx ? 'text-accent' : 'text-foreground'
                      }`}
                    >
                      {skill.stat}
                    </p>
                    <p className="text-xs text-muted-foreground font-mono uppercase tracking-wider mb-3">
                      {skill.label}
                    </p>

                    {/* Skill Name */}
                    <p className="text-sm font-medium text-foreground">
                      {skill.name}
                    </p>
                  </div>

                  {/* Bottom accent bar */}
                  <div
                    className={`absolute bottom-0 left-0 h-0.5 bg-accent transition-all duration-500 ease-out ${
                      hoveredSkill === idx ? 'w-full' : 'w-0'
                    }`}
                  />
                </div>
              </div>
            )
          })}
        </div>

        {/* Decorative floating elements */}
        <div className="relative mt-16 flex justify-center">
          <div
            className="flex items-center gap-3 px-6 py-3 rounded-full border border-accent/30 bg-card"
            style={{
              opacity: isVisible ? 1 : 0,
              transform: isVisible ? 'translateY(0)' : 'translateY(20px)',
              transition: 'all 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.9s',
            }}
          >
            <div className="w-2 h-2 rounded-full bg-accent animate-pulse" />
            <p className="text-sm text-muted-foreground font-mono">
              Currently open to new opportunities
            </p>
          </div>
        </div>
      </div>
    </section>
  )
}
